pub unsafe extern "C" fn sqlite3_set_authorizer(
    mut db: *mut crate::sqliteInt_h::sqlite3,
    mut xAuth: Option<
        unsafe extern "C" fn(
            *mut ::core::ffi::c_void,
            ::core::ffi::c_int,
            *const ::core::ffi::c_char,
            *const ::core::ffi::c_char,
            *const ::core::ffi::c_char,
            *const ::core::ffi::c_char,
        ) -> ::core::ffi::c_int,
    >,
    mut pArg: *mut ::core::ffi::c_void,
) -> ::core::ffi::c_int {
    crate::src::src::mutex::sqlite3_mutex_enter((*db).mutex);
    (*db).xAuth = xAuth;
    (*db).pAuthArg = pArg;
    if (*db).xAuth.is_some() {
        crate::src::src::vdbeaux::sqlite3ExpirePreparedStatements(db as *mut crate::sqliteInt_h::sqlite3, 1 as ::core::ffi::c_int);
    }
    crate::src::src::mutex::sqlite3_mutex_leave((*db).mutex);
    return crate::sqlite3_h::SQLITE_OK;
}

