    let mut iDb: ::core::ffi::c_int = 0;
    let mut iCol: ::core::ffi::c_int = 0;
    iDb = crate::src::src::prepare::sqlite3SchemaToIndex((*pParse).db as *mut crate::sqliteInt_h::sqlite3,  pSchema as *mut crate::sqliteInt_h::Schema);
